class Solution:
    def minimumAddedInteger(self, nums1, nums2) -> int:
        from itertools import combinations
        nums1s = sorted(nums1)
        nums2s = sorted(nums2)
        best = float('inf')
        for skip in combinations(range(len(nums1s)), 2):
            skip_set = set(skip)
            remaining = [nums1s[i] for i in range(len(nums1s)) if i not in skip_set]
            x = nums2s[0] - remaining[0]
            if all(remaining[i] + x == nums2s[i] for i in range(len(nums2s))):
                best = min(best, x)
        return best

