class Solution:
    def minimumAddedInteger(self, nums1, nums2) -> int:
        nums1.sort()
        nums2.sort()
        n1, n2 = len(nums1), len(nums2)
        best = float('inf')
        # The two skipped elements must be among the first 3 of sorted nums1
        for i in range(3):
            for j in range(i+1, 3):
                skip = {i, j}
                remaining = [nums1[k] for k in range(n1) if k not in skip]
                x = nums2[0] - remaining[0]
                if all(remaining[k] + x == nums2[k] for k in range(n2)):
                    best = min(best, x)
        return best

