var minimumAddedInteger = function(nums1, nums2) {
    nums1.sort((a,b) => a-b);
    nums2.sort((a,b) => a-b);
    const n1 = nums1.length, n2 = nums2.length;
    let best = Infinity;
    for (let i = 0; i < 3; i++) {
        for (let j = i+1; j < 3; j++) {
            const skip = new Set([i, j]);
            const remaining = nums1.filter((_, k) => !skip.has(k));
            const x = nums2[0] - remaining[0];
            if (remaining.every((v, k) => v + x === nums2[k])) {
                best = Math.min(best, x);
            }
        }
    }
    return best;
};
